import psycopg2
from psycopg2 import sql, extensions

def connect():
    conn = None
    try:
        # replace 'hostname', 'database_name', 'username', and 'password' with your database credentials.
        conn = psycopg2.connect(host="hostname", dbname="database_name", user="username", password="password")
    except psycopg2.DatabaseError as e:
        print(f"Unable to connect to the database: {e}")
    return conn

def close(conn):
    try:
        if conn is not None:
            conn.close()
    except psycopg2.DatabaseError as e:
        print(f"Failed to close connection: {e}")
        
def search_users(**kwargs):
    conn = connect()
    
    with conn.cursor() as cur:
        query = sql.SQL("SELECT * FROM users WHERE ")

        conditions = []

        if 'username' in kwargs:
            conditions.append(sql.SQL("username=%s"))
        
        if 'email' in kwargs:
            conditions.append(sql.SQL("email=%s"))
            
        if 'role' in kwargs:
            conditions.append(sql.SQL("role=%s"))
            
        if 'status' in kwargs:
            conditions.append(sql.SQL("status=%s"))
        
        query += sql.SQL(' AND '.join(conditions))
        cur.execute(query, list(kwargs.values()))
        
        rows = cur.fetchall()
    
    close(conn)

    return rows